### 병목 3: 매칭 점수 계산 로직을 JVM 메모리에서 반복 수행

**Before (문제 코드)**

```kotlin
// 매번 전체 대기 목록을 로드하고 JVM에서 필터/정렬 - 비효율적
fun rankCandidates(myProfile: UserProfile, candidates: List<CallMatchEntity>): List<CallMatchEntity> {
    return candidates
        .filter { it.userId != myProfile.userId }
        .filter { it.preferredGender == myProfile.gender }
        .sortedByDescending { calculateScore(myProfile, it) } // 매번 전체 재계산
}

private fun calculateScore(profile: UserProfile, candidate: CallMatchEntity): Int {
    // DB 조회 없이 계산 가능한 로직이지만
    // 후보가 많을수록 O(n) 비용 증가
    var score = 0
    if (candidate.ageMin <= profile.age && profile.age <= candidate.ageMax) score += 30
    // ... 추가 점수 계산
    return score
}
```

