### 개선 3: QueryDSL Projection으로 필요한 컬럼만 조회

**After (개선 코드)**

```kotlin
// domain/src/main/kotlin/com/maum/backend/repository/call/CallMatchQueryRepository.kt

@Repository
class CallMatchQueryRepository(
    private val queryFactory: JPAQueryFactory,
) {
    fun findMatchCandidatesProjection(
        preferredGender: String,
        excludeUserId: String,
        limit: Long = 20,
    ): List<MatchCandidateDto> {
        val match = QCallMatchEntity.callMatchEntity
        val profile = QUserProfileEntity.userProfileEntity

        return queryFactory
            .select(
                // Projection: 필요한 컬럼만 선택 (전체 Entity 로드 방지)
                Projections.constructor(
                    MatchCandidateDto::class.java,
                    match.id,
                    match.userId,
                    profile.nickname,
                    profile.age,
                    profile.thumbnailUrl,
                    match.createdAt,
                )
            )
            .from(match)
            .innerJoin(profile).on(match.userId.eq(profile.userId))
            .where(
                match.status.eq(1),                         // 대기중
                match.preferredGender.eq(preferredGender),  // 선호 성별 필터
                match.userId.ne(excludeUserId),             // 본인 제외
            )
            .orderBy(match.createdAt.asc())                 // 대기 오래된 순 (공정한 매칭)
            .limit(limit)
            .fetch()
    }
}
```

---

### 개선 4: CallMatchService 통합 - Redis 우선 조회 + DB Fallback

**After (개선 코드)**

```kotlin
// application/src/main/kotlin/com/maum/backend/service/call/CallMatchService.kt

@Service
@Transactional(readOnly = true)
class CallMatchService(
    private val callMatchCacheService: CallMatchCacheService,
    private val callMatchQueryRepository: CallMatchQueryRepository,
    private val callMatchRepository: CallMatchRepository,
) {
    fun findMatchCandidates(userId: String, preferredGender: String): List<MatchCandidateDto> {
        // 1순위: Redis 대기 큐에서 조회 (< 1ms)
        val cached = callMatchCacheService.dequeueCandidates(preferredGender)
        if (cached.isNotEmpty()) {
            return cached
                .filter { it.userId != userId }
                .map { it.toMatchCandidateDto() }
        }

        // 2순위: DB 조회 (Redis miss 시 fallback) + QueryDSL Projection
        return callMatchQueryRepository.findMatchCandidatesProjection(
            preferredGender = preferredGender,
            excludeUserId = userId,
            limit = 20,
        )
    }

    @Transactional
    fun enterMatchQueue(userId: String, gender: String, preferredGender: String) {
        // DB 저장
        val entity = CallMatchEntity(
            userId = userId,
            status = 1,
            preferredGender = preferredGender,
        )
        callMatchRepository.save(entity)

        // Redis 큐에도 동시 등록 (캐시 워밍)
        callMatchCacheService.enqueue(
            userId = userId,
            gender = preferredGender,
            waitingInfo = WaitingUserDto.from(entity),
        )
    }

    @Transactional
    fun completeMatch(matchId: String, userId1: String, userId2: String, gender: String) {
        // DB 상태 업데이트
        callMatchRepository.updateStatusByIds(listOf(matchId), status = 2)

        // Redis 큐에서 두 사용자 제거 (캐시 무효화)
        callMatchCacheService.removeFromQueue(userId1, gender)
        callMatchCacheService.removeFromQueue(userId2, gender)
    }
}
```

