## 4. 인덱스 마이그레이션 SQL

```sql
-- maum.call_match 테이블 인덱스 추가
-- 매칭 대기 목록 조회 최적화 (status + preferred_gender 복합 인덱스)
ALTER TABLE maum.call_match
    ADD INDEX idx_status_preferred_gender (status, preferred_gender),
    ADD INDEX idx_user_id (user_id),
    ADD INDEX idx_created_at (created_at);

-- EXPLAIN으로 인덱스 활용 확인
EXPLAIN SELECT * FROM maum.call_match
WHERE status = 1 AND preferred_gender = 'FEMALE'
ORDER BY created_at ASC
LIMIT 20;
```

