### 개선 2: Redis 기반 매칭 대기 큐 캐싱

**After (개선 코드)**

```kotlin
// application/src/main/kotlin/com/maum/backend/service/call/CallMatchCacheService.kt

@Service
class CallMatchCacheService(
    private val redisTemplate: RedisTemplate<String, String>,
    private val objectMapper: ObjectMapper,
) {
    companion object {
        // 키 설계: 성별별 대기 큐 분리
        private const val MATCH_QUEUE_KEY = "call:match:queue:{gender}"
        private const val MATCH_USER_KEY = "call:match:user:{userId}"
        private const val QUEUE_TTL_SECONDS = 30L    // 대기 큐 TTL 30초 (매칭 중 변경 빈도 높음)
        private const val USER_STATUS_TTL_SECONDS = 60L
    }

    // 대기 큐에 유저 등록 (ZSet 사용: score = 등록 시각으로 FIFO 보장)
    fun enqueue(userId: String, gender: String, waitingInfo: WaitingUserDto) {
        val queueKey = MATCH_QUEUE_KEY.replace("{gender}", gender)
        val userKey = MATCH_USER_KEY.replace("{userId}", userId)
        val now = System.currentTimeMillis().toDouble()

        redisTemplate.execute { connection ->
            connection.multi()
            // ZSet에 사용자 추가
            redisTemplate.opsForZSet().add(queueKey, userId, now)
            redisTemplate.expire(queueKey, Duration.ofSeconds(QUEUE_TTL_SECONDS))
            // 사용자 상세 정보 Hash 저장
            redisTemplate.opsForValue().set(
                userKey,
                objectMapper.writeValueAsString(waitingInfo),
                Duration.ofSeconds(USER_STATUS_TTL_SECONDS)
            )
            connection.exec()
        }
    }

    // 대기 큐에서 후보 N명 조회 (오래 기다린 순서)
    fun dequeueCandidates(preferredGender: String, limit: Long = 20): List<WaitingUserDto> {
        val queueKey = MATCH_QUEUE_KEY.replace("{gender}", preferredGender)

        // score 오름차순(대기 오래된 순) 조회
        val userIds = redisTemplate.opsForZSet().range(queueKey, 0, limit - 1) ?: emptySet()

        if (userIds.isEmpty()) return emptyList()

        // Pipeline으로 일괄 조회 (추가 N번 쿼리 방지)
        val pipeline = redisTemplate.executePipelined { conn ->
            userIds.forEach { uid ->
                conn.stringCommands().get(
                    MATCH_USER_KEY.replace("{userId}", uid).toByteArray()
                )
            }
        }

        return pipeline.filterNotNull().map { raw ->
            objectMapper.readValue(raw as String, WaitingUserDto::class.java)
        }
    }

    // 매칭 완료 시 큐에서 제거 (무효화)
    fun removeFromQueue(userId: String, gender: String) {
        val queueKey = MATCH_QUEUE_KEY.replace("{gender}", gender)
        val userKey = MATCH_USER_KEY.replace("{userId}", userId)
        redisTemplate.opsForZSet().remove(queueKey, userId)
        redisTemplate.delete(userKey)
    }
}
```

